                <th>Username</th>
                <td>{{ user.username }}</td>
            </tr>
            <tr>
                <th>Roles</th>
                <td>{% if \x27ROLE_USER\x27 in user.roles and \x27ROLE_ADMIN\x27 in user.roles %}
